SELECT po.id
FROM pay_order po
INNER JOIN dealer_sales_document sd ON sd.sales_document_id = po.sales_document_id
WHERE sd.del_flag = '0'

    AND sd.tenant_id = #{scopeTenantId}
    AND sd.business_origin = #{scopeBusinessOrigin}


    AND sd.business_origin = #{query.businessOrigin}




            AND sd.tenant_id = #{query.subjectId}


            AND sd.sales_store_id = #{query.subjectId}


            AND ((sd.business_origin = 'MERCHANT' AND sd.tenant_id = #{query.subjectId})
                OR (sd.business_origin = 'INTERNAL' AND sd.sales_store_id = #{query.subjectId}))




    AND (sd.order_no LIKE CONCAT('%', #{query.keyword}, '%')
        OR sd.source_no LIKE CONCAT('%', #{query.keyword}, '%')
        OR sd.customer_name LIKE CONCAT('%', #{query.keyword}, '%')
        OR sd.merchant_name LIKE CONCAT('%', #{query.keyword}, '%'))
    AND (po.no = #{query.keyword} OR po.sales_order_no = #{query.keyword})


    AND po.create_time >= #{query.beginTime}


    AND po.create_time <= #{query.endTime}


    AND po.channel_code = #{query.channelCode}


    AND po.status = #{query.status}

ORDER BY po.create_time DESC, po.id DESC

SELECT pe.id
FROM pay_order_extension pe
INNER JOIN pay_order po ON po.id = pe.order_id
INNER JOIN dealer_sales_document sd ON sd.sales_document_id = po.sales_document_id
WHERE sd.del_flag = '0'
    AND pe.channel_code = 'bank_transfer'

    AND sd.tenant_id = #{scopeTenantId}
    AND sd.business_origin = #{scopeBusinessOrigin}


    AND sd.business_origin = #{query.businessOrigin}




            AND sd.tenant_id = #{query.subjectId}


            AND sd.sales_store_id = #{query.subjectId}


            AND ((sd.business_origin = 'MERCHANT' AND sd.tenant_id = #{query.subjectId})
                OR (sd.business_origin = 'INTERNAL' AND sd.sales_store_id = #{query.subjectId}))




    AND (sd.order_no LIKE CONCAT('%', #{query.keyword}, '%')
        OR sd.source_no LIKE CONCAT('%', #{query.keyword}, '%')
        OR sd.customer_name LIKE CONCAT('%', #{query.keyword}, '%')
        OR sd.merchant_name LIKE CONCAT('%', #{query.keyword}, '%'))
    AND (pe.no = #{query.keyword}
        OR pe.bank_reference_no = #{query.keyword}
        OR po.no = #{query.keyword}
        OR po.sales_order_no = #{query.keyword})


    AND pe.bank_submitted_time >= #{query.beginTime}


    AND pe.bank_submitted_time <= #{query.endTime}


    AND pe.bank_transfer_status = #{query.status}



        ORDER BY pe.bank_submitted_time ASC, pe.id ASC


        ORDER BY pe.bank_reviewed_time DESC, pe.id DESC
